func Test_BatchEmbed(t *testing.T) {
	// Embedding request with multiple input strings returns one embedding object per input
	var request pkg.EmbeddingRequest
	if err := json.Unmarshal([]byte(`{"input":["Hello","World"],"model":"text-embedding-3-small"}`), &request); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	mockURL := os.Getenv("MOCK_SERVER_URL") + "/fixtures/batch_embed"
	client, clientErr := pkg.CreateClient("test-key", &mockURL, nil, nil, nil)
	if clientErr != nil {
		t.Fatalf("create client failed: %v", clientErr)
	}
	result, err := client.Embed(request)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	assert.Equal(t, len(result.Data), 2, "expected exactly 2 elements")
	if len(result.Data) > 0 {
		assert.Equal(t, len(result.Data[0].Embedding), 5, "expected exactly 5 elements")
	}
}

